class DSU {
public:
    std::vector<int> parent;
    // dist[i] stores the parity of the path weight from i to parent[i]
    std::vector<int> dist;
    int N;

    DSU(int n) : N(n) {
        parent.resize(n);
        dist.resize(n, 0);
        std::iota(parent.begin(), parent.end(), 0);
    }

    // Returns {root, parity_from_node_to_root}
    std::pair<int, int> find(int i) {
        if (parent[i] == i) {
            return {i, 0};
        }

        // Recursive call to find root and parity from parent[i] to root
        auto [root, parity_p_to_r] = find(parent[i]);

        // Path compression: Update parent[i] directly to root
        parent[i] = root;

        // Update dist[i]: New dist[i] = old dist[i] ^ parity_p_to_r
        // Old dist[i] was parity from i to old parent[i].
        // Now i -> root path is i -> old parent[i] -> root.
        dist[i] = dist[i] ^ parity_p_to_r;

        return {root, dist[i]};
    }

    // Tries to unite u and v with edge weight w.
    // Returns true if the edge is added (maintains cycle parity property), false otherwise.
    bool unite(int u, int v, int w) {
        auto [root_u, d_u] = find(u);
        auto [root_v, d_v] = find(v);

        if (root_u == root_v) {
            // u and v are already connected. Adding (u, v) creates a cycle.
            // Existing path parity u -> v is d_u ^ d_v.
            // Cycle parity = (d_u ^ d_v) ^ w.
            // We require cycle parity to be 0 (even).
            if ((d_u ^ d_v ^ w) == 1) {
                return false; // Odd cycle created
            }
            return true; // Even cycle created, acceptable
        } else {
            // Different components. Merge root_v into root_u.
            parent[root_v] = root_u;

            // We need to set dist[root_v], the parity of path root_v -> root_u.
            // We know:
            // 1. Path u -> root_u has parity d_u.
            // 2. Path v -> root_v has parity d_v.
            // 3. New edge u -> v has parity w.
            // We want: P(root_v -> root_u) such that:
