            // d(root_v) = P_RvRu
            // d(v) = P_RvRu ^ d_v

            // We require d(u) ^ d(v) = w
            // d_u ^ (P_RvRu ^ d_v) = w
            // P_RvRu = w ^ d_u ^ d_v

            dist[root_v] = w ^ d_u ^ d_v;
            return true;
        }
    }
};


