class DSU {
    constructor(n) {
        this.parent = Array(n).fill(0).map((_, i) => i);
        // diff[i] stores the parity of the path weight from i to parent[i].
        // For the root, this is conceptually 0.
        this.diff = Array(n).fill(0); 
    }

    // Returns [root, parity_from_i_to_root]
    find(i) {
        if (this.parent[i] === i) {
            return [i, 0];
        }

        // Recursive call
        const [root, parent_diff] = this.find(this.parent[i]);

        // Path compression update: 
        // New difference = (i -> old_parent) XOR (old_parent -> root)
        // old_parent -> root parity is parent_diff (relative to root)
        // i -> old_parent parity is this.diff[i] (relative to old_parent)
        this.diff[i] ^= parent_diff;
        this.parent[i] = root;

        return [root, this.diff[i]];
    }

    // Union operation based on edge (u, v) with weight w.
    // Returns true if the edge can be added (consistent), false otherwise.
    union(u, v, w) {
        const [rootU, diffU] = this.find(u);
        const [rootV, diffV] = this.find(v);

        if (rootU === rootV) {
            // Same component: Check for cycle parity
            // Cycle parity = (u -> root) XOR (v -> root) XOR (u -> v weight)
            const cycleParity = diffU ^ diffV ^ w;
            return cycleParity === 0;
        } else {
            // Different components: Merge V into U (arbitrarily)
            // We need to set parent[rootV] = rootU and determine the new diff[rootV].

            // We know:
            // u -> rootU has parity diffU
            // v -> rootV has parity diffV
            // Edge u -> v has weight w

            // We want R_v -> R_u parity. Path: R_v -> v -> u -> R_u
            // R_v -> v: parity diffV
            // v -> u: parity w
            // u -> R_u: parity diffU
            const newDiffRV = diffV ^ w ^ diffU;

            this.parent[rootV] = rootU;
            this.diff[rootV] = newDiffRV;

            return true;
        }
    }
}


function solve(n, edges) {
    const dsu = new DSU(n);
    let count = 0;

    for (const edge of edges) {
        const [u, v, w] = edge;

        // The union method handles both acceptance logic (Cycle check) and structure modification (Merge)
        if (dsu.union(u, v, w)) {
            count++;
        }
    }

    return count;
}
