    }

    // Find operation returns {root, path_parity_to_root}
    // path_parity_to_root is the XOR sum of weights on the path from i to root.
    std::pair<long long, int> Find(long long i) {
        if (parent[i] == i) {
            return {i, 0};
        }

        // Recurse first
        auto result = Find(parent[i]);
        long long root = result.first;
        int parity_to_root_from_parent = result.second;

        // Path compression and parity update
        // New parity[i] = (old parity[i] from i to old parent) XOR (parity_to_root_from_parent)
        parity[i] = parity[i] ^ parity_to_root_from_parent;
        parent[i] = root;

        return {root, parity[i]};
    }

    // Try to union u and v with weight w. 
    // Returns true if successful (no odd cycle formed or components merged), false otherwise.
    bool Union(long long u, long long v, int w) {
        auto result_u = Find(u);
        long long root_u = result_u.first;
        int d_u = result_u.second; // d(u, root_u)

        auto result_v = Find(v);
        long long root_v = result_v.first;
        int d_v = result_v.second; // d(v, root_v)

        if (root_u == root_v) {
