            // Cycle weight = d(u, v) [through tree path] + w
            // d(u, v) = d(u, root_u) XOR d(v, root_v) = d_u XOR d_v
            int cycle_weight_parity = d_u ^ d_v ^ w;

            // Must be even (0 mod 2)
            return cycle_weight_parity == 0;
        } else {
            // Different components, merge them.
            // Merge root_u into root_v (arbitrary choice, rank/size optimization omitted for simplicity but standard DSU works fine).

            parent[root_u] = root_v;

            // Calculate parity[root_u]: d(root_u, root_v)
            // Path: root_u -> u --w--> v -> root_v
