#include <vector>
#include <numeric>
#include <utility>

class DSU {
public:
    // parent[i]: parent of node i
    std::vector<long long> parent;
    // parity[i]: parity of the path distance from i to parent[i] (0 or 1)
    std::vector<int> parity; 
    int N;

    DSU(long long n) : N(n) {
        parent.resize(N);
        std::iota(parent.begin(), parent.end(), 0); // parent[i] = i
        parity.assign(N, 0); // Initial distance to self is 0
    }

    // Find operation returns {root, path_parity_to_root}
    // path_parity_to_root is the XOR sum of weights on the path from i to root.
    std::pair<long long, int> Find(long long i) {
        if (parent[i] == i) {
            return {i, 0};
        }

        // Recurse first
        auto result = Find(parent[i]);
        long long root = result.first;
        int parity_to_root_from_parent = result.second;

        // Path compression and parity update
        // New parity[i] = (old parity[i] from i to old parent) XOR (parity_to_root_from_parent)
        parity[i] = parity[i] ^ parity_to_root_from_parent;
        parent[i] = root;

        return {root, parity[i]};
    }

    // Try to union u and v with weight w. 
    // Returns true if successful (no odd cycle formed or components merged), false otherwise.
    bool Union(long long u, long long v, int w) {
        auto result_u = Find(u);
        long long root_u = result_u.first;
        int d_u = result_u.second; // d(u, root_u)

        auto result_v = Find(v);
        long long root_v = result_v.first;
        int d_v = result_v.second; // d(v, root_v)

        if (root_u == root_v) {
            // Same component, forms a cycle. Check consistency.
            // Path u to v via tree: d_u XOR d_v. Cycle weight = (d_u XOR d_v) XOR w.
            int cycle_weight_parity = d_u ^ d_v ^ w;

            // Must be even (0 mod 2)
            return cycle_weight_parity == 0;
        } else {
            // Different components, merge them.
            // Merge root_u into root_v.

            parent[root_u] = root_v;

            // Calculate parity[root_u]: d(root_u, root_v)
            // Path: root_u -> u --w--> v -> root_v
            // d(root_u, root_v) = d(root_u, u) XOR w XOR d(v, root_v)
            // Since d_u = d(u, root_u), d(root_u, u) = d_u.
            parity[root_u] = d_u ^ w ^ d_v;

            return true;
        }
    }
};

long long solve(long long n, std::vector<std::vector<long long>> edges) {
    DSU dsu(n);
    long long accepted_edges = 0;

    for (const auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        // Weights are 0 or 1, safely cast to int for parity arithmetic
        int w = (int)edge[2]; 

        if (dsu.Union(u, v, w)) {
            accepted_edges++;
        }
    }

    return accepted_edges;
}

