#include <vector>
#include <numeric>

class DSU_Parity {
private:
    std::vector<int> parent;
    // diff[i] stores the parity of the path weight from i to parent[i]
    // d(i) ^ d(parent[i]) = diff[i]
    std::vector<int> diff; 

public:
    DSU_Parity(int n) {
        parent.resize(n);
        std::iota(parent.begin(), parent.end(), 0);
        diff.assign(n, 0);
    }

    // Finds the root of i and updates diff[i] to store d(i) ^ d(root)
    int find(int i) {
        if (parent[i] == i) {
            return i;
        }

        int root = find(parent[i]);

        // Update diff[i]: 
        // New diff[i] = (d(i) ^ d(parent[i])) ^ (d(parent[i]) ^ d(root))
        // The second term d(parent[i]) ^ d(root) is now stored in diff[parent[i]] after recursive call
        diff[i] = diff[i] ^ diff[parent[i]];

        parent[i] = root;
        return root;
    }

    // Unites the sets containing u and v, applying the constraint w = d(u) ^ d(v)
    // Returns true if they were merged (or consistent if already merged), false if inconsistency detected.
    bool unite(int u, int v, int w) {
        int root_u = find(u);
        int root_v = find(v);

        if (root_u != root_v) {
            // Merge V's set into U's set (arbitrary choice)
            parent[root_v] = root_u;

            // We need to set diff[root_v] = d(root_v) ^ d(root_u)
            // We know:
            // d(u) ^ d(v) = w  (New edge constraint)
            // d(u) = d(root_u) ^ diff[u]
            // d(v) = d(root_v) ^ diff[v]

            // Substitute:
            // (d(root_u) ^ diff[u]) ^ (d(root_v) ^ diff[v]) = w
            // d(root_u) ^ d(root_v) = w ^ diff[u] ^ diff[v]

            // Since parent[root_v] = root_u, diff[root_v] must be d(root_v) ^ d(root_u)
            diff[root_v] = w ^ diff[u] ^ diff[v];
            return true;
        } else {
            // Same component, check consistency
            // Required parity D = d(u) ^ d(v) = diff[u] ^ diff[v]
            int required_parity = diff[u] ^ diff[v];

            // If w equals the required parity, the cycle is even.
            return (w == required_parity);
        }
    }
};


long long solve(long long n, std::vector<std::vector<long long>> edges) {
    // N is up to 5*10^4, fits in int for array indexing.
    int N_int = (int)n;

    DSU_Parity dsu(N_int);
    long long added_edges_count = 0;

    for (const auto& edge : edges) {
        // u_i, v_i, w_i
        int u = (int)edge[0];
        int v = (int)edge[1];
        int w = (int)edge[2];

        // Try to unite/check consistency
        bool success = dsu.unite(u, v, w);

        if (success) {
            added_edges_count++;
        }
    }

    return added_edges_count;
}
