class DSU {
    constructor(n) {
        this.parent = Array(n).fill(0).map((_, i) => i);
        // diff[i] stores the parity of the path weight from i to its current representative (root).
        this.diff = Array(n).fill(0); 
    }

    // Returns [root, parity_from_i_to_root]
    find(i) {
        if (this.parent[i] === i) {
            return [i, 0];
        }

        // Recursive call to find root and parity from parent to root
        const [root, parent_diff] = this.find(this.parent[i]);

        // Path compression update: 
        // New difference = (i -> old_parent) XOR (old_parent -> root)
        this.diff[i] ^= parent_diff;
        this.parent[i] = root;

        return [root, this.diff[i]];
    }

    // Union operation based on edge (u, v) with weight w.
    // Returns true if the edge maintains the even cycle property, false otherwise.
    union(u, v, w) {
        const [rootU, diffU] = this.find(u);
        const [rootV, diffV] = this.find(v);

        if (rootU === rootV) {
            // Same component: Check for cycle parity
            // Cycle parity = (u -> root) XOR (v -> root) XOR (u -> v weight)
            const cycleParity = diffU ^ diffV ^ w;
            return cycleParity === 0;
        } else {
            // Different components: Merge V's component into U's component (union by rank/size omitted for simplicity but path compression is present)

            // We set parent[rootV] = rootU. We need to calculate the new diff[rootV], 
            // which is the parity of the path rootV -> rootU.
            // Path: rootV -> v (parity diffV) -> u (weight w) -> rootU (parity diffU)
            const newDiffRV = diffV ^ w ^ diffU;

            this.parent[rootV] = rootU;
            this.diff[rootV] = newDiffRV;

            return true;
        }
    }
}

function solve(n, edges) {
    const dsu = new DSU(n);
    let count = 0;

    for (const edge of edges) {
        const [u, v, w] = edge;

        if (dsu.union(u, v, w)) {
            count++;
        }
    }

    return count;
}
